1296     } else {
1297       const SCEV *NarrowLHS = SE->getSCEV(NarrowUse->getOperand(0));
1298       WideLHS = GetExtend(NarrowLHS, WideType);
1299       WideRHS = SE->getSCEV(WideDef);
