620 /// Replace the UseInst with a loop invariant expression if it is safe.
621 bool SimplifyIndvar::replaceIVUserWithLoopInvariant(Instruction *I) {
622   if (!SE->isSCEVable(I->getType()))
623     return false;
624 
625   // Get the symbolic expression for this instruction.
626   const SCEV *S = SE->getSCEV(I);
627 
628   if (!SE->isLoopInvariant(S, L))
629     return false;
630 
631   // Do not generate something ridiculous even if S is loop invariant.
632   if (Rewriter.isHighCostExpansion(S, L, SCEVCheapExpansionBudget, TTI, I))
633     return false;
